const appointments = $input.all().map(i => i.json);
const today = new Date().toISOString().split('T')[0];
const tomorrow = new Date(Date.now() + 24 * 60 * 60 * 1000).toISOString().split('T')[0];

// Today's appointments
const todayApts = appointments
  .filter(a => a.date === today && a.status === 'confirmed')
  .sort((a, b) => (a.time || '').localeCompare(b.time || ''));

// Tomorrow's appointments
const tomorrowApts = appointments
  .filter(a => a.date === tomorrow && a.status === 'confirmed')
  .sort((a, b) => (a.time || '').localeCompare(b.time || ''));

// Build HTML tables
function buildTable(apts, label) {
  if (apts.length === 0) return `<p><strong>${label}:</strong> No appointments scheduled.</p>`;
  let html = `<h3>${label} (${apts.length} appointments)</h3>`;
  html += '<table border="1" cellpadding="8" cellspacing="0"><tr><th>Time</th><th>Client</th><th>Service</th><th>Phone</th><th>Notes</th></tr>';
  for (const a of apts) {
    html += `<tr><td><strong>${a.time}</strong></td><td>${a.name}</td><td>${a.service}</td><td>${a.phone}</td><td>${a.notes || '-'}</td></tr>`;
  }
  html += '</table>';
  return html;
}

const todayTable = buildTable(todayApts, `Today (${today})`);
const tomorrowTable = buildTable(tomorrowApts, `Tomorrow (${tomorrow})`);

// Weekly stats
const weekStart = new Date(Date.now() - new Date().getDay() * 24 * 60 * 60 * 1000).toISOString().split('T')[0];
const thisWeek = appointments.filter(a => a.date >= weekStart);
const completed = thisWeek.filter(a => a.showed_up === 'true' || a.showed_up === true).length;
const noShows = thisWeek.filter(a => a.status === 'no-show').length;
const cancelled = thisWeek.filter(a => a.status === 'cancelled').length;

return [{
  json: {
    today_date: today,
    today_count: todayApts.length,
    tomorrow_count: tomorrowApts.length,
    today_table: todayTable,
    tomorrow_table: tomorrowTable,
    week_completed: completed,
    week_noshows: noShows,
    week_cancelled: cancelled
  }
}];
